#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10;
int ch[N<<1][26],fa[N<<1],len[N<<1],cnt=1,lst=1;
struct Graph
{
	int head[N<<1],des[N<<1],nxt[N<<1],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
}a;
inline void ins(int c)
{
	int p=lst, np=lst=++cnt;len[np]=len[p]+1;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;
	if(!p)fa[np]=1;
 	else
 	{
 		int v=ch[p][c];
 		if(len[v]==len[p]+1)fa[np]=v;
 		else
 		{
 			int nv=++cnt;len[nv]=len[p]+1;
 			fa[nv]=fa[v];memcpy(ch[nv],ch[v],sizeof(ch[v]));
 			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
 			fa[np]=fa[v]=nv;
		}
	}
}
long long n,m,ans;char s[N];
inline void dfs(int u)
{
	if(len[u]>=m){++ans;return;}
	else grep(a,u,i)dfs(a.des[i]);
}
int main()
{
	n=read();scanf("%s",s+1);
	rep(1,n,i)ins(s[i]-'a');
	rep(2,cnt,i)ans+=len[i]-len[fa[i]];
	printf("%lld\n",ans);
	return 0;
}
